// ── Pre-baked logo PNGs: generated from logo.svg at build time ──
// Dark card: all logo elements recoloured to white on transparent
// Light card: all logo elements recoloured to #0f172a on transparent
// These are used during html2canvas capture (which ignores CSS filters)
const _LOGO_DARK_B64  = "data:image/png;base64,";
const _LOGO_LIGHT_B64 = "data:image/png;base64,";

async function _smCapture() {
  const card  = document.getElementById('sm-card');
  const fit   = document.getElementById('sm-card-fit');
  const theme = card.classList.contains('light') ? 'light' : 'dark';
  const logoDataUrl = theme === 'light' ? _LOGO_LIGHT_B64 : _LOGO_DARK_B64;

  // The live preview shrinks/grows #sm-card-fit with a CSS transform so it
  // fits inside whatever frame shape is selected. That's purely a preview
  // convenience — the actual export must always capture the card at its
  // real, untransformed size (cardScale below already handles resolution),
  // so temporarily neutralize the transform for the capture.
  const fitPrevTransform = fit ? fit.style.transform : null;
  if (fit) fit.style.transform = 'none';

  // Swap all logo img srcs to the pre-baked PNG data URL
  const logoImgs   = Array.from(card.querySelectorAll('img[src*="logo"]'));
  const origSrcs   = logoImgs.map(img => img.getAttribute('src'));
  const origStyles = logoImgs.map(img => img.style.cssText);

  logoImgs.forEach(img => {
    img.setAttribute('src', logoDataUrl);
    img.style.filter  = 'none';
    img.style.opacity = '1';
  });

  let cardCanvas;
  const preset = SM_SIZE_PRESETS[_shareSizePreset] || SM_SIZE_PRESETS.ig_square;
  try {
    // Two frames for browser to paint
    await new Promise(r => requestAnimationFrame(() => requestAnimationFrame(r)));

    // Capture the card itself at a resolution sharp enough to still look
    // crisp once it's scaled to fit inside the target canvas below —
    // independent of the preset's aspect ratio, since the card's own
    // design proportions never change, only how it's composited.
    const cardScale = Math.max(2, Math.min(4, preset.w / card.offsetWidth, preset.h / card.offsetHeight));
    cardCanvas = await html2canvas(card, {
      scale: cardScale,
      useCORS: true,
      backgroundColor: null,
      logging: false,
      allowTaint: true,
      imageTimeout: 5000,
      onclone: (doc) => {
        doc.querySelectorAll('.sm-card-logo').forEach(el => {
          el.setAttribute('src', logoDataUrl);
          el.style.filter  = 'none';
          el.style.opacity = '1';
        });
        // html2canvas can't resolve <svg><use href="#ic-x"> sprite refs, so
        // any icon rendered via icon() (checklist ticks, star rating, etc.)
        // came out blank in the exported image despite showing fine in the
        // live preview. Inline each icon's real markup from the live sprite
        // before capture so it rasterizes correctly.
        const clonedCard = doc.getElementById('sm-card');
        if (clonedCard) {
          clonedCard.querySelectorAll('svg.icn use').forEach(useEl => {
            const href  = useEl.getAttribute('href') || useEl.getAttribute('xlink:href') || '';
            const symId = href.replace('#', '');
            const sym   = symId ? document.getElementById(symId) : null;
            const svg   = useEl.closest('svg');
            if (!sym || !svg) return;
            const vb = sym.getAttribute('viewBox');
            if (vb) svg.setAttribute('viewBox', vb);
            svg.innerHTML = sym.innerHTML;
          });
        }
      },
    });
  } finally {
    // Restore — always, even if html2canvas threw, so the live preview
    // doesn't get stuck at its natural (untransformed, oversized) footprint.
    logoImgs.forEach((img, i) => {
      img.setAttribute('src', origSrcs[i]);
      img.style.cssText = origStyles[i];
    });
    if (fit) fit.style.transform = fitPrevTransform || '';
  }

  // Composite onto an export canvas that is EXACTLY the selected preset's
  // pixel dimensions. smSyncCardHeight already gave #sm-card this exact
  // same w:h ratio before capture, so cardCanvas already has (up to
  // sub-pixel rounding) the preset's own aspect ratio — there is no
  // mismatched shape left to "fit" inside a padded backdrop. We draw it
  // straight to the full canvas edge-to-edge instead: no matte border, no
  // letterboxing, and no distortion, since source and destination ratios
  // already match — this is what actually fills the card flush to the
  // frame for every preset, including the tall Portrait/Phone Story ones.
  const out = document.createElement('canvas');
  out.width  = preset.w;
  out.height = preset.h;
  const ctx = out.getContext('2d');
  ctx.drawImage(cardCanvas, 0, 0, preset.w, preset.h);

  return out;
}
async function smDownload(){
  _smSetLoading('sm-dl-btn','sm-dl-spin','sm-dl-lbl',true);
  try{const t=trades.find(x=>x.id===_shareTradeId),filename=`NxTGen_${(t||{pair:'Trade'}).pair}_${(t||{date:'trade'}).date}`,canvas=await _smCapture();
    if(_shareFmt==='pdf'){const{jsPDF}=window.jspdf,pdf=new jsPDF({orientation:'portrait',unit:'mm',format:'a4'}),pw=pdf.internal.pageSize.getWidth(),iw=pw-30,ih=(canvas.height/canvas.width)*iw;pdf.addImage(canvas.toDataURL('image/jpeg',0.96),'JPEG',15,20,iw,ih);pdf.save(filename+'.pdf');}
    else if(_shareFmt==='png'){const link=document.createElement('a');link.download=filename+'.png';link.href=canvas.toDataURL('image/png');link.click();}
    else{const link=document.createElement('a');link.download=filename+'.jpg';link.href=canvas.toDataURL('image/jpeg',0.96);link.click();}
    showToast('Trade card saved!','success');
  }catch(e){console.error(e);showToast('Export failed — try again','danger');}
  _smSetLoading('sm-dl-btn','sm-dl-spin','sm-dl-lbl',false,'<svg class="icn" aria-hidden="true"><use href="#ic-download"></use></svg> Download');
}
async function smShareNative(){
  _smSetLoading('sm-share-btn','sm-share-spin','sm-share-lbl',true);
  try{const t=trades.find(x=>x.id===_shareTradeId),canvas=await _smCapture();
    canvas.toBlob(async blob=>{const file=new File([blob],`NxTGen_${(t||{pair:'Trade'}).pair}.jpg`,{type:'image/jpeg'}),shareData={files:[file],title:`NxTGen · ${(t||{}).pair}`,text:`${(t||{}).pair} ${(t||{}).pos} · ${(t||{}).pnl>=0?'+':''}${(t||{}).pnl}% — NxTGen Journal`};
      if(navigator.canShare&&navigator.canShare(shareData)){try{await navigator.share(shareData);showToast('Shared!','success');}catch(e){if(e.name!=='AbortError')_smClipboardFallback(canvas);}}
      else _smClipboardFallback(canvas);
      _smSetLoading('sm-share-btn','sm-share-spin','sm-share-lbl',false,'<svg class="icn" aria-hidden="true"><use href="#ic-link"></use></svg> Share');
    },'image/jpeg',0.96);
  }catch(e){console.error(e);showToast('Share failed','danger');_smSetLoading('sm-share-btn','sm-share-spin','sm-share-lbl',false,'<svg class="icn" aria-hidden="true"><use href="#ic-link"></use></svg> Share');}
}
function _smClipboardFallback(canvas){canvas.toBlob(async blob=>{try{await navigator.clipboard.write([new ClipboardItem({'image/png':blob})]);showToast('Copied to clipboard!','success');}catch{const l=document.createElement('a');l.download='NxTGen_Trade.jpg';l.href=canvas.toDataURL('image/jpeg',0.96);l.click();showToast('Saved!','success');};},'image/png');}
function _smEnsureLibs(cb){if(typeof html2canvas!=='undefined'&&typeof window.jspdf!=='undefined'){cb();return;}const h2c=document.createElement('script');h2c.src='https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js';h2c.onload=()=>{const jpdf=document.createElement('script');jpdf.src='https://cdnjs.cloudflare.com/ajax/libs/jspdf/2.5.1/jspdf.umd.min.js';jpdf.onload=cb;document.head.appendChild(jpdf);};document.head.appendChild(h2c);}

