//  PROFILE — Cloud-synced via journal_profiles Supabase table
//  Table DDL (run once in Supabase SQL editor):
//
//  CREATE TABLE IF NOT EXISTS journal_profiles (
//    id          uuid PRIMARY KEY DEFAULT gen_random_uuid(),
//    user_id     uuid REFERENCES auth.users(id) ON DELETE CASCADE NOT NULL UNIQUE,
//    fname       text, lname text, display_name text, phone text,
//    timezone    text, bio text, address text,
//    exp         text, market text, session text, risk text,
//    daterange   text, currency text, weekstart text, defaultview text,
//    affirmation boolean DEFAULT true,
//    sounds      boolean DEFAULT false,
//    compact     boolean DEFAULT false,
//    autosave    boolean DEFAULT true,
//    avatar_url  text,
//    updated_at  timestamptz DEFAULT now()
//  );
//  ALTER TABLE journal_profiles ENABLE ROW LEVEL SECURITY;
//  CREATE POLICY "Users manage own profile"
//    ON journal_profiles FOR ALL USING (auth.uid() = user_id);
// ════════════════════════════════════════════════════════════════════

// _profileData / _profileRowId are declared near the top of the file
// (right after the Supabase client is created) — see comment there.

async function _profileLoad() {
  if (!_currentUser) return;
  const { data, error } = await sb
    .from('journal_profiles')
    .select('*')
    .eq('user_id', _currentUser.id)
    .maybeSingle();
  if (error) { console.error('profileLoad:', error.message); return; }

  if (data) {
    _profileRowId = data.id;
    _profileData  = data;
    _profileMigrateBase64Avatar(); // fire-and-forget backfill, see below
  } else {
    // First login — seed from auth metadata
    const meta = _currentUser.user_metadata || {};
    const fullName = meta.full_name || '';
    const parts    = fullName.trim().split(/\s+/);
    _profileData = {
      fname:        parts[0] || '',
      lname:        parts.slice(1).join(' ') || '',
      display_name: fullName,
      phone:        meta.phone || '',
      timezone:     'Africa/Lagos',
      bio:          '',
      address:      '',
      exp:          'Intermediate (1–3 yrs)',
      market:       'Forex',
      session:      'London',
      risk:         '1%',
      daterange:    'This Quarter',
      currency:     '% (Percentage)',
      weekstart:    'Sunday',
      defaultview:  'Quarterly',
      affirmation:  true,
      sounds:       false,
      compact:      false,
      autosave:     true,
      avatar_url:   meta.avatar_url || '',
    };
    // Persist the seed immediately
    await _profileSave();
  }
}

/* ── Backfill: migrate a legacy base64 avatar_url (from before the
   compress+Storage path existed) out to Storage. Safe to call repeatedly. */
async function _profileMigrateBase64Avatar() {
  if (!_currentUser || !_profileData.avatar_url) return;
  if (!_profileData.avatar_url.startsWith('data:image')) return;
  try {
    const res  = await fetch(_profileData.avatar_url);
    const blob = await res.blob();
    const compressed = await _compressChartImage(blob, 400, 0.85);
    const path = `avatars/${_currentUser.id}/avatar_${Date.now()}.jpg`;
    const { error } = await sb.storage.from('trade-charts')
      .upload(path, compressed, { upsert: true, contentType: 'image/jpeg' });
    if (error) { console.error('avatar migration upload error:', error.message); return; }
    const { data: urlData } = sb.storage.from('trade-charts').getPublicUrl(path);
    _profileData.avatar_url = urlData.publicUrl;
    await _profileSave();
    _profileApplyAvatar(_profileData.avatar_url);
    console.info('Profile: migrated legacy base64 avatar to Storage.');
  } catch (err) {
    console.error('avatar migration failed:', err.message || err);
  }
}

async function _profileSave() {
  if (!_currentUser) return;
  const row = {
    user_id:      _currentUser.id,
    ..._profileData,
    updated_at:   new Date().toISOString(),
  };
  delete row.id; // don't send PK in payload
  if (_profileRowId) {
    const { error } = await sb.from('journal_profiles').update(row).eq('id', _profileRowId);
    if (error) { showToast('Save failed: ' + error.message, 'danger'); return false; }
  } else {
    const { data, error } = await sb.from('journal_profiles').insert(row).select('id').single();
    if (error) { showToast('Save failed: ' + error.message, 'danger'); return false; }
    if (data) _profileRowId = data.id;
  }
  return true;
}

